class Solution:
    def numMusicPlaylists(self, n: int, goal: int, k: int) -> int:
        MOD = 10**9 + 7
        from functools import lru_cache
        @lru_cache(maxsize=None)
        def dp(i, j):
            # i songs played, j distinct songs used
            if i == 0:
                return 1 if j == 0 else 0
            # Add a new song
            res = dp(i - 1, j - 1) * (n - (j - 1)) % MOD if j > 0 else 0
            # Replay an old song (need j - k choices > 0)
            if j > k:
                res = (res + dp(i - 1, j) * (j - k)) % MOD
            return res
        return dp(goal, n)

